 14→
 15→// itemType represents the type of MCP item (tool, prompt, or resource)
 16→type itemType string
 17→
 18→const (
 19→	itemTypeTool     itemType = "tool"
 20→	itemTypePrompt   itemType = "prompt"
 21→	itemTypeResource itemType = "resource"
 22→)
 23→
 24→// activeItemManager manages the active state of MCP items (tools, prompts, resources)
 25→type activeItemManager struct {
 26→	mu       sync.RWMutex
 27→	items    map[string]bool
 28→	itemType itemType
 29→}
 30→
 31→// newActiveItemManager creates a new active item manager
 32→func newActiveItemManager(iType itemType) *activeItemManager {
 33→	return &activeItemManager{
 34→		items:    make(map[string]bool),
 35→		itemType: iType,
 36→	}
 37→}
 38→
 39→// isActive checks if an item is active
 40→func (m *activeItemManager) isActive(name string) bool {
 41→	m.mu.RLock()
 42→	defer m.mu.RUnlock()
 43→	return m.items[name]
 44→}
 45→
 46→// setActive marks an item as active
 47→func (m *activeItemManager) setActive(name string, active bool) {
 48→	m.mu.Lock()
 49→	defer m.mu.Unlock()
 50→	if active {
 51→		m.items[name] = true
 52→	} else {
 53→		delete(m.items, name)
 54→	}
 55→}
 56→
 57→// getInactiveItems returns items that are no longer in the new set
 58→func (m *activeItemManager) getInactiveItems(newItems map[string]struct{}) []string {
 59→	m.mu.RLock()
 60→	defer m.mu.RUnlock()
 61→
 62→	var inactive []string
 63→	for name := range m.items {
 64→		if _, exists := newItems[name]; !exists {
 65→			inactive = append(inactive, name)
 66→		}
 67→	}
 68→	return inactive
 69→}
 70→
 71→// removeItems removes the specified items from the active set
 72→func (m *activeItemManager) removeItems(items []string) {
 73→	m.mu.Lock()
 74→	defer m.mu.Unlock()
 75→	for _, item := range items {
 76→		delete(m.items, item)
 77→	}
 78→}
 79→
 80→// collectResult holds the results of collecting items from servers
 81→type collectResult struct {
 82→	newTools     map[string]struct{}
 83→	newPrompts   map[string]struct{}
 84→	newResources map[string]struct{}
 85→}
 86→
 87→// collectItemsFromServers collects all items from connected servers and auth_required servers
 88→func collectItemsFromServers(servers map[string]*ServerInfo, registry *ServerRegistry) *collectResult {
 89→	result := &collectResult{
 90→		newTools:     make(map[string]struct{}),
 91→		newPrompts:   make(map[string]struct{}),
 92→		newResources: make(map[string]struct{}),
 93→	}
 94→
 95→	for serverName, info := range servers {
 96→		// Handle servers requiring authentication - collect synthetic auth tools
 97→		if info.Status == StatusAuthRequired {
 98→			info.mu.RLock()
 99→			for _, tool := range info.Tools {
100→				exposedName := registry.nameTracker.GetExposedToolName(serverName, tool.Name)
101→				result.newTools[exposedName] = struct{}{}
102→			}
103→			info.mu.RUnlock()
104→			continue
105→		}
106→
107→		if !info.IsConnected() {
108→			continue
109→		}
110→
111→		info.mu.RLock()
112→		// Collect tools
113→		for _, tool := range info.Tools {
114→			exposedName := registry.nameTracker.GetExposedToolName(serverName, tool.Name)
115→			result.newTools[exposedName] = struct{}{}
116→		}
117→		// Collect prompts
118→		for _, prompt := range info.Prompts {
119→			exposedName := registry.nameTracker.GetExposedPromptName(serverName, prompt.Name)
120→			result.newPrompts[exposedName] = struct{}{}
121→		}
122→		// Collect resources
123→		for _, resource := range info.Resources {
124→			exposedURI := registry.nameTracker.GetExposedResourceURI(serverName, resource.URI)
125→			result.newResources[exposedURI] = struct{}{}
126→		}
127→		info.mu.RUnlock()
128→	}
129→
130→	return result
131→}
132→
133→// collectItemsFromServersAndProviders collects all items from connected servers AND core providers
134→func collectItemsFromServersAndProviders(servers map[string]*ServerInfo, registry *ServerRegistry, a *AggregatorServer) *collectResult {
135→	// Start with regular server items
136→	result := collectItemsFromServers(servers, registry)
137→
138→	// Add core tools from providers (workflow, orchestrator, config, mcp)
139→	// These are the tools that get added by createToolsFromProviders()
140→	coreTools := a.createToolsFromProviders()
141→	for _, tool := range coreTools {
142→		result.newTools[tool.Tool.Name] = struct{}{}
143→	}
144→
145→	return result
146→}
