257→// toolHandlerFactory creates a handler for a tool
258→func toolHandlerFactory(a *AggregatorServer, exposedName string) func(context.Context, mcp.CallToolRequest) (*mcp.CallToolResult, error) {
259→	return func(ctx context.Context, req mcp.CallToolRequest) (*mcp.CallToolResult, error) {
260→		// Note: Per ADR-008, synthetic auth tools are no longer used.
261→		// Users must use core_auth_login to authenticate to OAuth-protected servers.
262→
263→		// Check if this tool is still active
264→		if !a.toolManager.isActive(exposedName) {
265→			return nil, fmt.Errorf("tool '%s' is no longer available", exposedName)
266→		}
267→
268→		// Resolve the exposed name back to server and original tool name
269→		sName, originalName, err := a.registry.ResolveToolName(exposedName)
270→		if err != nil {
271→			// If not found in registry, check session connections for OAuth-protected servers
272→			sessionID := getSessionIDFromContext(ctx)
273→			serverName, client, origName, resolveErr := a.resolveSessionTool(sessionID, exposedName)
274→			if resolveErr != nil {
275→				return nil, fmt.Errorf("failed to resolve tool name: %w", err)
276→			}
277→			// Found in session connection - call through the session-specific client
278→			args := make(map[string]interface{})
279→			if req.Params.Arguments != nil {
280→				if argsMap, ok := req.Params.Arguments.(map[string]interface{}); ok {
281→					args = argsMap
282→				}
283→			}
284→			result, callErr := client.CallTool(ctx, origName, args)
285→			if callErr != nil {
286→				if is401Error(callErr) {
287→					logging.Warn("Aggregator", "Tool call to %s got 401 for session %s - token expired/refresh failed",
288→						serverName, logging.TruncateSessionID(sessionID))
289→					return nil, fmt.Errorf("authentication to %s expired - please re-authenticate and try again", serverName)
290→				}
291→				return nil, fmt.Errorf("tool execution failed: %w", callErr)
292→			}
293→			return result, nil
294→		}
295→
296→		// Check if tool is destructive and yolo mode is not enabled
297→		if !a.config.Yolo && isDestructiveTool(originalName) {
298→			logging.Warn("Aggregator", "Blocked destructive tool call: %s (enable --yolo flag to allow)", originalName)
299→			return nil, fmt.Errorf("tool '%s' is blocked as it is destructive. Use --yolo flag to allow destructive operations", originalName)
300→		}
301→
302→		// Check if this server is OAuth-protected and needs session-specific client
303→		serverInfo, exists := a.registry.GetServerInfo(sName)
304→		if exists && serverInfo.Status == StatusAuthRequired {
305→			// This is an OAuth-protected server - get the client from session connection
306→			sessionID := getSessionIDFromContext(ctx)
307→			session := a.sessionRegistry.GetOrCreateSession(sessionID)
308→			conn, hasConn := session.GetConnection(sName)
309→			if !hasConn || conn.Client == nil {
310→				return nil, fmt.Errorf("not authenticated to server %s", sName)
311→			}
312→
313→			// Forward the request using the session-specific client
314→			// The client uses DynamicAuthClient which automatically refreshes tokens
315→			args := make(map[string]interface{})
316→			if req.Params.Arguments != nil {
317→				if argsMap, ok := req.Params.Arguments.(map[string]interface{}); ok {
318→					args = argsMap
319→				}
320→			}
321→
322→			result, err := conn.Client.CallTool(ctx, originalName, args)
323→			if err != nil {
324→				if is401Error(err) {
325→					logging.Warn("Aggregator", "Tool call to %s got 401 for session %s - token expired/refresh failed",
326→						sName, logging.TruncateSessionID(sessionID))
327→					return nil, fmt.Errorf("authentication to %s expired - please re-authenticate and try again", sName)
328→				}
329→				return nil, fmt.Errorf("tool execution failed: %w", err)
330→			}
331→			return result, nil
332→		}
333→
334→		// Get the backend client from the global registry (for non-OAuth servers)
335→		client, err := a.registry.GetClient(sName)
336→		if err != nil {
337→			return nil, fmt.Errorf("server not available: %w", err)
338→		}
339→
340→		// Forward the request with the original tool name
341→		args := make(map[string]interface{})
342→		if req.Params.Arguments != nil {
343→			if argsMap, ok := req.Params.Arguments.(map[string]interface{}); ok {
344→				args = argsMap
345→			}
346→		}
347→
348→		result, err := client.CallTool(ctx, originalName, args)
349→		if err != nil {
350→			return nil, fmt.Errorf("tool execution failed: %w", err)
351→		}
352→
353→		return result, nil
354→	}
355→}
