357→// promptHandlerFactory creates a handler for a prompt
358→func promptHandlerFactory(a *AggregatorServer, exposedName string) func(context.Context, mcp.GetPromptRequest) (*mcp.GetPromptResult, error) {
359→	return func(ctx context.Context, req mcp.GetPromptRequest) (*mcp.GetPromptResult, error) {
360→		// Check if this prompt is still active
361→		if !a.promptManager.isActive(exposedName) {
362→			return nil, fmt.Errorf("prompt %s is no longer available", exposedName)
363→		}
364→
365→		// Resolve the exposed name back to server and original prompt name
366→		sName, originalName, err := a.registry.ResolvePromptName(exposedName)
367→		if err != nil {
368→			return nil, fmt.Errorf("failed to resolve prompt name: %w", err)
369→		}
370→
371→		// Get the backend client
372→		client, err := a.registry.GetClient(sName)
373→		if err != nil {
374→			return nil, fmt.Errorf("server not available: %w", err)
375→		}
376→
377→		// Forward the request with the original prompt name
378→		args := make(map[string]interface{})
379→		if req.Params.Arguments != nil {
380→			for k, v := range req.Params.Arguments {
381→				args[k] = v
382→			}
383→		}
384→
385→		result, err := client.GetPrompt(ctx, originalName, args)
386→		if err != nil {
387→			return nil, fmt.Errorf("prompt retrieval failed: %w", err)
388→		}
389→
390→		return result, nil
391→	}
392→}
