394→// resourceHandlerFactory creates a handler for a resource
395→func resourceHandlerFactory(a *AggregatorServer, exposedURI string) func(context.Context, mcp.ReadResourceRequest) ([]mcp.ResourceContents, error) {
396→	return func(ctx context.Context, req mcp.ReadResourceRequest) ([]mcp.ResourceContents, error) {
397→		// Check if this resource is still active
398→		if !a.resourceManager.isActive(exposedURI) {
399→			return nil, fmt.Errorf("resource %s is no longer available", exposedURI)
400→		}
401→
402→		// Resolve the exposed URI back to server and original URI
403→		sName, originalURI, err := a.registry.ResolveResourceName(exposedURI)
404→		if err != nil {
405→			return nil, fmt.Errorf("failed to resolve resource URI: %w", err)
406→		}
407→
408→		// Get the backend client
409→		client, err := a.registry.GetClient(sName)
410→		if err != nil {
411→			return nil, fmt.Errorf("server not available: %w", err)
412→		}
413→
414→		// Forward the request with the original URI
415→		result, err := client.ReadResource(ctx, originalURI)
416→		if err != nil {
417→			return nil, fmt.Errorf("resource read failed: %w", err)
418→		}
419→
420→		var contents []mcp.ResourceContents
421→		if result != nil && len(result.Contents) > 0 {
422→			contents = result.Contents
423→		}
424→		return contents, nil
425→	}
426→}
