428→// processToolsForServer processes all tools from a server and returns handlers to add
429→func processToolsForServer(a *AggregatorServer, serverName string, info *ServerInfo) []mcpserver.ServerTool {
430→	info.mu.RLock()
431→	defer info.mu.RUnlock()
432→
433→	results := processItemsGeneric(
434→		a,
435→		serverName,
436→		info.Tools,
437→		itemTypeTool,
438→		a.toolManager,
439→		a.registry.nameTracker.GetExposedToolName,
440→		func(agg *AggregatorServer, exposedName string) interface{} {
441→			return toolHandlerFactory(agg, exposedName)
442→		},
443→	)
444→
445→	// Convert results to []mcpserver.ServerTool
446→	var toolsToAdd []mcpserver.ServerTool
447→	for _, item := range results {
448→		if tool, ok := item.(mcpserver.ServerTool); ok {
449→			toolsToAdd = append(toolsToAdd, tool)
450→		}
451→	}
452→	return toolsToAdd
453→}
