509→// enrichMCPServerWithSessionData adds session-specific state to an MCPServerInfo.
510→// This includes the session's connection status, authentication status, and tools count.
511→//
512→// Args:
513→//   - serverInfo: The MCPServerInfo map from the mcpserver_list response
514→//   - session: The session state (may be nil if no session)
515→//
516→// Returns the enriched serverInfo map with session fields added.
517→func enrichMCPServerWithSessionData(serverInfo map[string]interface{}, session *SessionState) map[string]interface{} {
518→	if session == nil {
519→		return serverInfo
520→	}
521→
522→	serverName, ok := serverInfo["name"].(string)
523→	if !ok || serverName == "" {
524→		return serverInfo
525→	}
526→
527→	conn, hasConn := session.GetConnection(serverName)
528→	if !hasConn || conn == nil {
529→		// No session connection - leave session fields empty
530→		return serverInfo
531→	}
532→
533→	// Add session status (using thread-safe getter)
534→	serverInfo["sessionStatus"] = string(conn.GetStatus())
535→
536→	// Add auth status (only for non-empty values)
537→	authStatus := conn.GetAuthStatus()
538→	if authStatus != "" && authStatus != AuthStatusUnknown {
539→		serverInfo["sessionAuth"] = string(authStatus)
540→	}
541→
542→	// Add connected timestamp if available (using thread-safe getter)
543→	connectedAt := conn.GetConnectedAt()
544→	if !connectedAt.IsZero() {
545→		serverInfo["connectedAt"] = connectedAt
546→	}
547→
548→	// Add tools count from session connection
549→	tools := conn.GetTools()
550→	if len(tools) > 0 {
551→		serverInfo["toolsCount"] = len(tools)
552→	}
553→
554→	return serverInfo
555→}
