557→// enrichMCPServerListResponse enriches the mcpserver_list response with session-specific data.
558→// It modifies the response in place to add sessionStatus, sessionAuth, toolsCount, and connectedAt
559→// fields to each server based on the current session's connection state.
560→//
561→// Args:
562→//   - result: The mcp.CallToolResult from mcpserver_list
563→//   - session: The session state (may be nil if no session)
564→//
565→// Returns the enriched result.
566→func enrichMCPServerListResponse(result *mcp.CallToolResult, session *SessionState) *mcp.CallToolResult {
567→	if session == nil || result == nil || len(result.Content) == 0 {
568→		return result
569→	}
570→
571→	// The mcpserver_list response has Content containing a map with "mcpServers" array
572→	for i, content := range result.Content {
573→		textContent, ok := content.(mcp.TextContent)
574→		if !ok {
575→			continue
576→		}
577→
578→		// Parse the JSON content
579→		var responseMap map[string]interface{}
580→		if err := json.Unmarshal([]byte(textContent.Text), &responseMap); err != nil {
581→			logging.Debug("ServerHelpers", "Failed to parse mcpserver_list response: %v", err)
582→			continue
583→		}
584→
585→		// Find the mcpServers array
586→		servers, ok := responseMap["mcpServers"].([]interface{})
587→		if !ok {
588→			logging.Debug("ServerHelpers", "mcpserver_list response missing 'mcpServers' array, skipping session enrichment")
589→			continue
590→		}
591→
592→		// Enrich each server with session data
593→		for j, server := range servers {
594→			serverMap, ok := server.(map[string]interface{})
595→			if !ok {
596→				logging.Debug("ServerHelpers", "mcpserver_list server at index %d is not a map, skipping", j)
597→				continue
598→			}
599→			servers[j] = enrichMCPServerWithSessionData(serverMap, session)
600→		}
601→		responseMap["mcpServers"] = servers
602→
603→		// Re-serialize and update the content
604→		enrichedJSON, err := json.Marshal(responseMap)
605→		if err != nil {
606→			logging.Debug("ServerHelpers", "Failed to serialize enriched response: %v", err)
607→			continue
608→		}
609→
610→		result.Content[i] = mcp.TextContent{
611→			Type: "text",
612→			Text: string(enrichedJSON),
613→		}
614→	}
615→
616→	return result
617→}
618→

140→		// Server is already connected or doesn't require auth
141→		if serverInfo.IsConnected() {
142→			return &api.CallToolResult{
143→				Content: []interface{}{fmt.Sprintf("Server '%s' is already authenticated and connected.", serverName)},
144→				IsError: false,
145→			}, nil
