148→// removeObsoleteItems is a generic function to remove items that no longer exist
149→func removeObsoleteItems(
150→	manager *activeItemManager,
151→	newItems map[string]struct{},
152→	removeFunc func(items []string),
153→) {
154→	itemsToRemove := manager.getInactiveItems(newItems)
155→
156→	if len(itemsToRemove) > 0 {
157→		logging.Debug("Aggregator", "Removing %d %ss: %v", len(itemsToRemove), manager.itemType, itemsToRemove)
158→		removeFunc(itemsToRemove)
159→		manager.removeItems(itemsToRemove)
160→	}
161→}
