163→// itemInfo represents a generic MCP item (tool, prompt, or resource)
164→type itemInfo struct {
165→	itemType     itemType
166→	name         string      // Name for tools/prompts, URI for resources
167→	originalItem interface{} // The original mcp.Tool, mcp.Prompt, or mcp.Resource
168→}
169→
170→// getItemIdentifier returns the identifier for an item (name or URI)
171→func getItemIdentifier(item interface{}) string {
172→	switch v := item.(type) {
173→	case mcp.Tool:
174→		return v.Name
175→	case mcp.Prompt:
176→		return v.Name
177→	case mcp.Resource:
178→		return v.URI
179→	default:
180→		return ""
181→	}
182→}
183→
184→// processItemsGeneric is a generic function to process any type of MCP item
185→func processItemsGeneric[T any](
186→	a *AggregatorServer,
187→	serverName string,
188→	items []T,
189→	iType itemType,
190→	manager *activeItemManager,
191→	getExposedName func(string, string) string,
192→	createHandler func(*AggregatorServer, string) interface{},
193→) []interface{} {
194→	var itemsToAdd []interface{}
195→
196→	for _, item := range items {
197→		// Get the item identifier
198→		originalID := getItemIdentifier(item)
199→		if originalID == "" {
200→			continue
201→		}
202→
203→		// Get exposed name/URI
204→		exposedID := getExposedName(serverName, originalID)
205→
206→		// Check if already active
207→		if manager.isActive(exposedID) {
208→			continue
209→		}
210→
211→		// Mark as active
212→		manager.setActive(exposedID, true)
213→
214→		// Create exposed item with updated identifier
215→		var exposedItem interface{}
216→		switch v := any(item).(type) {
217→		case mcp.Tool:
218→			tool := v
219→			tool.Name = exposedID
220→			exposedItem = tool
221→		case mcp.Prompt:
222→			prompt := v
223→			prompt.Name = exposedID
224→			exposedItem = prompt
225→		case mcp.Resource:
226→			resource := v
227→			resource.URI = exposedID
228→			exposedItem = resource
229→		}
230→
231→		// Create handler
232→		handler := createHandler(a, exposedID)
233→
234→		// Add to batch based on type
235→		switch iType {
236→		case itemTypeTool:
237→			itemsToAdd = append(itemsToAdd, mcpserver.ServerTool{
238→				Tool:    exposedItem.(mcp.Tool),
239→				Handler: handler.(func(context.Context, mcp.CallToolRequest) (*mcp.CallToolResult, error)),
240→			})
241→		case itemTypePrompt:
242→			itemsToAdd = append(itemsToAdd, mcpserver.ServerPrompt{
243→				Prompt:  exposedItem.(mcp.Prompt),
244→				Handler: handler.(func(context.Context, mcp.GetPromptRequest) (*mcp.GetPromptResult, error)),
245→			})
246→		case itemTypeResource:
247→			itemsToAdd = append(itemsToAdd, mcpserver.ServerResource{
248→				Resource: exposedItem.(mcp.Resource),
249→				Handler:  handler.(func(context.Context, mcp.ReadResourceRequest) ([]mcp.ResourceContents, error)),
250→			})
251→		}
252→	}
253→
254→	return itemsToAdd
255→}
