257→// toolHandlerFactory creates a handler for a tool
258→func toolHandlerFactory(a *AggregatorServer, exposedName string) func(context.Context, mcp.CallToolRequest) (*mcp.CallToolResult, error) {
259→	return func(ctx context.Context, req mcp.CallToolRequest) (*mcp.CallToolResult, error) {
260→		// Note: Per ADR-008, synthetic auth tools are no longer used.
261→		// Users must use core_auth_login to authenticate to OAuth-protected servers.
262→
263→		// Check if this tool is still active
264→		if !a.toolManager.isActive(exposedName) {
265→			return nil, fmt.Errorf("tool '%s' is no longer available", exposedName)
266→		}
267→
268→		// Resolve the exposed name back to server and original tool name
269→		sName, originalName, err := a.registry.ResolveToolName(exposedName)
270→		if err != nil {
271→			// If not found in registry, check session connections for OAuth-protected servers
272→			sessionID := getSessionIDFromContext(ctx)
273→			serverName, origName, resolveErr := a.resolveSessionTool(sessionID, exposedName)
274→			if resolveErr != nil {
275→				return nil, fmt.Errorf("failed to resolve tool name: %w", err)
276→			}
277→			// Found in session connection - create on-demand client for tool execution
278→			client, cleanup, clientErr := a.getOrCreateClientForToolCall(ctx, serverName, sessionID)
279→			if clientErr != nil {
280→				return nil, fmt.Errorf("failed to connect to server %s: %w", serverName, clientErr)
281→			}
282→			defer cleanup()
283→
284→			args := make(map[string]interface{})
285→			if req.Params.Arguments != nil {
286→				if argsMap, ok := req.Params.Arguments.(map[string]interface{}); ok {
287→					args = argsMap
288→				}
289→			}
290→			result, callErr := client.CallTool(ctx, origName, args)
291→			if callErr != nil {
292→				if is401Error(callErr) {
293→					logging.Warn("Aggregator", "Tool call to %s got 401 for session %s - token expired/refresh failed",
294→						serverName, logging.TruncateSessionID(sessionID))
295→					return nil, fmt.Errorf("authentication to %s expired - please re-authenticate and try again", serverName)
296→				}
297→				return nil, fmt.Errorf("tool execution failed: %w", callErr)
298→			}
299→			return result, nil
300→		}
301→
302→		// Check if tool is destructive and yolo mode is not enabled
303→		if !a.config.Yolo && isDestructiveTool(originalName) {
304→			logging.Warn("Aggregator", "Blocked destructive tool call: %s (enable --yolo flag to allow)", originalName)
305→			return nil, fmt.Errorf("tool '%s' is blocked as it is destructive. Use --yolo flag to allow destructive operations", originalName)
306→		}
307→
308→		// Check if this server is OAuth-protected and needs session-specific client
309→		serverInfo, exists := a.registry.GetServerInfo(sName)
310→		if exists && serverInfo.Status == StatusAuthRequired {
311→			// This is an OAuth-protected server - create on-demand client
312→			sessionID := getSessionIDFromContext(ctx)
313→			session := a.sessionRegistry.GetOrCreateSession(sessionID)
314→			conn, hasConn := session.GetConnection(sName)
315→			if !hasConn || conn.Status != StatusSessionConnected {
316→				return nil, fmt.Errorf("not authenticated to server %s", sName)
317→			}
318→
319→			// Create an on-demand client for this tool call
320→			client, cleanup, clientErr := a.getOrCreateClientForToolCall(ctx, sName, sessionID)
321→			if clientErr != nil {
322→				return nil, fmt.Errorf("failed to connect to server %s: %w", sName, clientErr)
323→			}
324→			defer cleanup()
325→
326→			args := make(map[string]interface{})
327→			if req.Params.Arguments != nil {
328→				if argsMap, ok := req.Params.Arguments.(map[string]interface{}); ok {
329→					args = argsMap
330→				}
331→			}
332→
333→			result, err := client.CallTool(ctx, originalName, args)
334→			if err != nil {
335→				if is401Error(err) {
336→					logging.Warn("Aggregator", "Tool call to %s got 401 for session %s - token expired/refresh failed",
337→						sName, logging.TruncateSessionID(sessionID))
338→					return nil, fmt.Errorf("authentication to %s expired - please re-authenticate and try again", sName)
339→				}
340→				return nil, fmt.Errorf("tool execution failed: %w", err)
341→			}
342→			return result, nil
343→		}
344→
345→		// Get the backend client from the global registry (for non-OAuth servers)
346→		client, err := a.registry.GetClient(sName)
347→		if err != nil {
348→			return nil, fmt.Errorf("server not available: %w", err)
349→		}
350→
351→		// Forward the request with the original tool name
352→		args := make(map[string]interface{})
353→		if req.Params.Arguments != nil {
354→			if argsMap, ok := req.Params.Arguments.(map[string]interface{}); ok {
355→				args = argsMap
356→			}
357→		}
358→
359→		result, err := client.CallTool(ctx, originalName, args)
360→		if err != nil {
361→			return nil, fmt.Errorf("tool execution failed: %w", err)
362→		}
363→
364→		return result, nil
365→	}
366→}
