368→// promptHandlerFactory creates a handler for a prompt
369→func promptHandlerFactory(a *AggregatorServer, exposedName string) func(context.Context, mcp.GetPromptRequest) (*mcp.GetPromptResult, error) {
370→	return func(ctx context.Context, req mcp.GetPromptRequest) (*mcp.GetPromptResult, error) {
371→		// Check if this prompt is still active
372→		if !a.promptManager.isActive(exposedName) {
373→			return nil, fmt.Errorf("prompt %s is no longer available", exposedName)
374→		}
375→
376→		// Resolve the exposed name back to server and original prompt name
377→		sName, originalName, err := a.registry.ResolvePromptName(exposedName)
378→		if err != nil {
379→			return nil, fmt.Errorf("failed to resolve prompt name: %w", err)
380→		}
381→
382→		// Get the backend client
383→		client, err := a.registry.GetClient(sName)
384→		if err != nil {
385→			return nil, fmt.Errorf("server not available: %w", err)
386→		}
387→
388→		// Forward the request with the original prompt name
389→		args := make(map[string]interface{})
390→		if req.Params.Arguments != nil {
391→			for k, v := range req.Params.Arguments {
392→				args[k] = v
393→			}
394→		}
395→
396→		result, err := client.GetPrompt(ctx, originalName, args)
397→		if err != nil {
398→			return nil, fmt.Errorf("prompt retrieval failed: %w", err)
399→		}
400→
401→		return result, nil
402→	}
403→}
