405→// resourceHandlerFactory creates a handler for a resource
406→func resourceHandlerFactory(a *AggregatorServer, exposedURI string) func(context.Context, mcp.ReadResourceRequest) ([]mcp.ResourceContents, error) {
407→	return func(ctx context.Context, req mcp.ReadResourceRequest) ([]mcp.ResourceContents, error) {
408→		// Check if this resource is still active
409→		if !a.resourceManager.isActive(exposedURI) {
410→			return nil, fmt.Errorf("resource %s is no longer available", exposedURI)
411→		}
412→
413→		// Resolve the exposed URI back to server and original URI
414→		sName, originalURI, err := a.registry.ResolveResourceName(exposedURI)
415→		if err != nil {
416→			return nil, fmt.Errorf("failed to resolve resource URI: %w", err)
417→		}
418→
419→		// Get the backend client
420→		client, err := a.registry.GetClient(sName)
421→		if err != nil {
422→			return nil, fmt.Errorf("server not available: %w", err)
423→		}
424→
425→		// Forward the request with the original URI
426→		result, err := client.ReadResource(ctx, originalURI)
427→		if err != nil {
428→			return nil, fmt.Errorf("resource read failed: %w", err)
429→		}
430→
431→		var contents []mcp.ResourceContents
432→		if result != nil && len(result.Contents) > 0 {
433→			contents = result.Contents
434→		}
435→		return contents, nil
436→	}
437→}
