439→// processToolsForServer processes all tools from a server and returns handlers to add
440→func processToolsForServer(a *AggregatorServer, serverName string, info *ServerInfo) []mcpserver.ServerTool {
441→	info.mu.RLock()
442→	defer info.mu.RUnlock()
443→
444→	results := processItemsGeneric(
445→		a,
446→		serverName,
447→		info.Tools,
448→		itemTypeTool,
449→		a.toolManager,
450→		a.registry.nameTracker.GetExposedToolName,
451→		func(agg *AggregatorServer, exposedName string) interface{} {
452→			return toolHandlerFactory(agg, exposedName)
453→		},
454→	)
455→
456→	// Convert results to []mcpserver.ServerTool
457→	var toolsToAdd []mcpserver.ServerTool
458→	for _, item := range results {
459→		if tool, ok := item.(mcpserver.ServerTool); ok {
460→			toolsToAdd = append(toolsToAdd, tool)
461→		}
462→	}
463→	return toolsToAdd
